function showError(e,t){hideError(e),e.insertAdjacentHTML("afterend",`<div class="error"><p>${t}</p></div>`)}function hideError(e){const t=e.nextElementSibling;t&&t.classList.contains("error")&&t.remove()}const body=document.getElementById("body");function showNotification(e,t){const n=document.createElement("div");n.textContent=e,n.classList.add("notification"),n.classList.add(t),body.appendChild(n),setTimeout(()=>n.remove(),2e3)}function getCsrfToken(){const e=document.querySelector('meta[name="csrf-token"]');return e?e.content:""}